-        (PredicatedBBsAfterVectorization[VF].count(BI->getSuccessor(0)) ||
-         PredicatedBBsAfterVectorization[VF].count(BI->getSuccessor(1))) &&
-        BI->getParent() != TheLoop->getLoopLatch())
