-  for (auto VF = ElementCount::getFixed(1);
-       ElementCount::isKnownLE(VF, MaxFactors.FixedVF); VF *= 2)
-    VFCandidates.push_back(VF);
-  for (auto VF = ElementCount::getScalable(1);
